func solve(nums []int64) []int64 {
	n := len(nums)
	ans := make([]int64, 2*n)

	// First half: ans[i] = nums[i]
	for i := 0; i < n; i++ {
		ans[i] = nums[i]
	}

	// Second half: ans[i + n] = nums[n - i - 1] for 0 <= i <= n - 1
	for i := 0; i < n; i++ {
		// The index for the reversed part is (n - 1 - i)
		// This is equivalent to iterating through the reversed nums array:
		// When i=0, we want nums[n-1] -> ans[n]
		// When i=1, we want nums[n-2] -> ans[n+1]
		// ...
		// When i=n-1, we want nums[0] -> ans[2n-1]
		reverse_index := n - 1 - i
		ans[n+i] = nums[reverse_index]
	}

	return ans
}

